import { describe, expect, it } from "vitest";
import { BlockNoteEditor, BlockNoteSchema, PartialBlock } from "@blocknote/core";
import { ColumnBlock, ColumnListBlock } from "../packages/xl-multi-column/src/blocks/Columns/index.js";

const schema = BlockNoteSchema.create().extend({
  blockSpecs: {
    column: ColumnBlock,
    columnList: ColumnListBlock,
  } as const,
});

const doc: PartialBlock<
  typeof schema.blockSchema,
  typeof schema.inlineContentSchema,
  typeof schema.styleSchema
>[] = [
  {
    id: "columns",
    type: "columnList",
    children: [
      {
        id: "column-1",
        type: "column",
        children: [{ id: "column-p-1", type: "paragraph", content: "One" }],
      },
      {
        id: "column-2",
        type: "column",
        children: [{ id: "column-p-2", type: "paragraph", content: "Two" }],
      },
      {
        id: "column-3",
        type: "column",
        children: [{ id: "column-p-3", type: "paragraph", content: "Three" }],
      },
    ],
  },
  { id: "after", type: "paragraph", content: "aaa" },
];

describe("temporary reproduction: Backspace after columnList", () => {
  it("should delete text instead of moving the block into the columnList", () => {
    const editor = BlockNoteEditor.create({ schema });
    const div = document.createElement("div");
    editor.mount(div);
    editor.replaceBlocks(editor.document, doc);
    editor.setTextCursorPosition("after", "end");

    const before = JSON.stringify(editor.document);
    expect(() => {
      for (let i = 0; i < 3; i++) {
        editor._tiptapEditor.commands.keyboardShortcut("Backspace");
      }
    }).not.toThrow();

    const afterBlock = editor.document.find((block) => block.id === "after");
    console.log("before", before);
    console.log("after", JSON.stringify(editor.document));
    expect(afterBlock?.type).toBe("paragraph");
    expect(afterBlock?.content).toEqual([]);

    editor._tiptapEditor.destroy();
  });
});
EOF
